package scraper

const platformFaviconMIME = "image/png"

var platformFaviconBase64 = map[string]string{
	PlatformID69Shuba:         "",
	PlatformIDBilibili:        "",
	PlatformIDDouban:          "",
	PlatformIDDouyin:          "",
	PlatformIDFanqieNovel:     "",
	PlatformIDIqiyi:           "",
	PlatformIDMGTV:            "",
	PlatformIDOfficialAccount: "",
	PlatformIDQidian:          "",
	PlatformIDQQ:              "",
	PlatformIDQuanben:         "",
	PlatformIDTelegram:        "",
	PlatformIDTikTok:          "",
	PlatformIDTMDB:            "",
	PlatformIDTTK:             "",
	PlatformIDV2EX:            "",
	PlatformIDWxChannels:      "",
	PlatformIDXiaohongshu:     "",
	PlatformIDYouTube:         "",
	PlatformIDYouku:           "",
	PlatformIDZhihu:           "",
}

func FaviconBase64(platformID string) string {
	platform, ok := Lookup(platformID)
	if !ok {
		return ""
	}
	if platform.ID == PlatformIDMQidian {
		return platformFaviconBase64[PlatformIDQidian]
	}
	return platformFaviconBase64[platform.ID]
}

func FaviconDataURL(platformID string) string {
	base64 := FaviconBase64(platformID)
	if base64 == "" {
		return ""
	}
	return "data:" + platformFaviconMIME + ";base64," + base64
}
